import { useState, useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import Footer from "./Footer";
import { getOrders } from "../features/user/userSlice";
import { Link, useNavigate } from "react-router-dom";
import { RiShoppingBag3Line, RiUserHeartLine, RiUserLine, RiMapPinLine, RiLogoutBoxLine } from "react-icons/ri";

function MyAccount() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const userState = useSelector((state) => state?.auth);
  const orderState = useSelector((state) => state?.auth?.getorderedProduct?.orders);
  
  const [user, setUser] = useState(null);

  useEffect(() => {
    const stored = localStorage.getItem("customer");
    if (stored) setUser(JSON.parse(stored));
    
    const token = stored ? JSON.parse(stored).token : "";
    const config = {
      headers: { Authorization: `Bearer ${token}`, Accept: "application/json" },
    };
    dispatch(getOrders(config));
  }, [dispatch]);

  const handleLogout = () => {
    localStorage.clear();
    window.location.href = "/";
  };

  const stats = [
    { label: "Total Orders", value: orderState?.length || 0, icon: <RiShoppingBag3Line />, color: "#14b8a6", link: "/orders" },
    { label: "Active Orders", value: orderState?.filter(o => o.orderStatus !== "delivered").length || 0, icon: <RiShoppingBag3Line />, color: "#3b82f6", link: "/orders" },
    { label: "Wishlist", value: userState?.wishlist?.length || 0, icon: <RiUserHeartLine />, color: "#f43f5e", link: "/wishlist" },
  ];

  const menuItems = [
    { title: "Order History", sub: "View and track your previous orders", icon: <RiShoppingBag3Line />, link: "/orders" },
    { title: "Personal Profile", sub: "Update your name, email, and mobile", icon: <RiUserLine />, link: "/profile" },
    { title: "Shipping Address", sub: "Manage your delivery locations", icon: <RiMapPinLine />, link: "/profile" },
    { title: "My Wishlist", sub: "Items you've saved for later", icon: <RiUserHeartLine />, link: "/wishlist" },
  ];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800;900&display=swap');
        
        @keyframes dashFade { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
        
        .dash-page { font-family: 'Outfit', sans-serif; background: #f8fafc; min-height: 100vh; padding-bottom: 100px; }
        
        .dash-hero {
          background: linear-gradient(135deg, #0f172a 0%, #134e4a 100%);
          padding: 80px 24px 120px;
          text-align: center;
          position: relative;
          clip-path: ellipse(150% 100% at 50% 0%);
        }
        
        .dash-container { max-width: 1100px; margin: -60px auto 0; padding: 0 20px; position: relative; z-index: 10; }
        
        .dash-stats-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 16px; margin-bottom: 32px; }
        .dash-stat-card {
           background: #fff; border-radius: 24px; padding: 24px;
           box-shadow: 0 4px 20px rgba(0,0,0,0.04);
           display: flex; align-items: center; gap: 16px;
           animation: dashFade 0.5s ease both;
           text-decoration: none; border: 1px solid #f1f5f9;
        }
        .dash-stat-icon {
          width: 48px; height: 48px; border-radius: 14px;
          display: flex; align-items: center; justify-content: center;
          font-size: 22px; color: #fff;
        }
        
        .dash-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 20px; }
        .dash-menu-card {
          background: #fff; border-radius: 24px; padding: 24px;
          display: flex; align-items: center; gap: 18px;
          border: 1px solid #f1f5f9; text-decoration: none;
          transition: all 0.3s ease;
          animation: dashFade 0.6s ease both;
        }
        .dash-menu-card:hover { transform: translateY(-4px); border-color: #14b8a6; box-shadow: 0 12px 32px rgba(0,0,0,0.06); }
        .dash-menu-icon {
          width: 54px; height: 54px; border-radius: 16px;
          background: #f0fdfa; color: #14b8a6;
          display: flex; align-items: center; justify-content: center; font-size: 24px;
        }
        .dash-menu-title { font-size: 17px; font-weight: 800; color: #1e293b; margin: 0 0 2px; }
        .dash-menu-sub { font-size: 13px; color: #94a3b8; font-weight: 500; margin: 0; }
        
        .dash-logout {
          margin-top: 40px; display: inline-flex; align-items: center; gap: 10px;
          padding: 14px 32px; background: #fff; color: #ef4444;
          border: 1.5px solid #fee2e2; border-radius: 16px;
          font-weight: 800; font-size: 14px; cursor: pointer;
          transition: all 0.2s;
        }
        .dash-logout:hover { background: #fef2f2; border-color: #fca5a5; transform: scale(0.98); }

        @media (max-width: 768px) {
          .dash-hero { padding: 40px 20px 60px; }
          .dash-container { margin-top: -30px; }
          .dash-stats-grid { grid-template-columns: 1fr; gap: 12px; }
          .dash-stat-card { padding: 16px; border-radius: 20px; gap: 12px; }
          .dash-stat-icon { width: 40px; height: 40px; font-size: 18px; border-radius: 12px; }
          .dash-stat-card div div:first-child { font-size: 9px !important; }
          .dash-stat-card div div:last-child { font-size: 20px !important; }
          
          .dash-grid { grid-template-columns: 1fr; gap: 12px; }
          .dash-menu-card { padding: 16px; border-radius: 20px; gap: 14px; }
          .dash-menu-icon { width: 44px; height: 44px; font-size: 20px; border-radius: 12px; }
          .dash-menu-title { font-size: 15px; }
          .dash-menu-sub { font-size: 11px; }
          
          .dash-logout { width: 100%; border-radius: 20px; padding: 12px; margin-top: 24px; }
        }
      `}</style>

      <main className="dash-page">
        <section className="dash-hero">
          <div style={{ position: "relative", zIndex: 2 }}>
            <div style={{ 
              width: 80, height: 80, borderRadius: "50%", background: "rgba(255,255,255,0.1)", 
              border: "3px solid rgba(255,255,255,0.2)", margin: "0 auto 20px",
              display: "flex", alignItems: "center", justifyCenter: "center", fontSize: 32, color: "#fff"
            }}>
              {user?.firstname?.charAt(0) || "U"}
            </div>
            <h1 style={{ color: "#fff", fontWeight: 900, fontSize: "clamp(2rem, 5vw, 3rem)", letterSpacing: "-1px", margin: "0 0 8px" }}>
              Hello, {user?.firstname || "Member"}!
            </h1>
            <p style={{ color: "rgba(255,255,255,0.6)", fontSize: 14, fontWeight: 500 }}>
              Welcome back to your Pulse Healthcare dashboard
            </p>
          </div>
        </section>

        <div className="dash-container">
          {/* Stats Section */}
          <div className="dash-stats-grid">
            {stats.map((s, i) => (
              <Link to={s.link} key={i} className="dash-stat-card" style={{ animationDelay: i * 0.1 + "s" }}>
                <div className="dash-stat-icon" style={{ background: s.color }}>{s.icon}</div>
                <div>
                  <div style={{ fontSize: 11, fontWeight: 800, textTransform: "uppercase", color: "#94a3b8", letterSpacing: "0.1em" }}>{s.label}</div>
                  <div style={{ fontSize: 24, fontWeight: 900, color: "#1e293b" }}>{s.value}</div>
                </div>
              </Link>
            ))}
          </div>

          {/* Quick Menu */}
          <div className="dash-grid">
            {menuItems.map((m, i) => (
              <Link to={m.link} key={i} className="dash-menu-card" style={{ animationDelay: (0.3 + i * 0.1) + "s" }}>
                <div className="dash-menu-icon">{m.icon}</div>
                <div>
                  <h3 className="dash-menu-title">{m.title}</h3>
                  <p className="dash-menu-sub">{m.sub}</p>
                </div>
              </Link>
            ))}
          </div>

          {/* Account Status Cards */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))", gap: 16, marginTop: 24 }}>
            {/* Email Verification Status */}
            <div style={{
              background: "#fff", borderRadius: 20, padding: "20px 24px",
              border: `1.5px solid ${user?.isEmailVerified ? "#d1fae5" : "#fde68a"}`,
              display: "flex", alignItems: "center", gap: 16,
              boxShadow: "0 2px 12px rgba(0,0,0,0.04)"
            }}>
              <div style={{
                width: 48, height: 48, borderRadius: 14, flexShrink: 0,
                background: user?.isEmailVerified ? "#ecfdf5" : "#fffbeb",
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: 22
              }}>
                {user?.isEmailVerified ? "✅" : "📧"}
              </div>
              <div>
                <div style={{ fontSize: 11, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.1em", color: "#94a3b8" }}>
                  Email Status
                </div>
                <div style={{ fontSize: 16, fontWeight: 800, color: user?.isEmailVerified ? "#059669" : "#d97706", marginTop: 2 }}>
                  {user?.isEmailVerified ? "Verified" : "Not Verified"}
                </div>
                {!user?.isEmailVerified && (
                  <div style={{ fontSize: 11, color: "#b45309", fontWeight: 600, marginTop: 2 }}>
                    Check your inbox to verify
                  </div>
                )}
              </div>
            </div>

            {/* B2B Access Status */}
            <div style={{
              background: "#fff", borderRadius: 20, padding: "20px 24px",
              border: `1.5px solid ${user?.customerType ? "#bfdbfe" : "#e2e8f0"}`,
              display: "flex", alignItems: "center", gap: 16,
              boxShadow: "0 2px 12px rgba(0,0,0,0.04)"
            }}>
              <div style={{
                width: 48, height: 48, borderRadius: 14, flexShrink: 0,
                background: user?.customerType ? "#eff6ff" : "#f8fafc",
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: 22
              }}>
                🏥
              </div>
              <div>
                <div style={{ fontSize: 11, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.1em", color: "#94a3b8" }}>
                  B2B / Wholesale
                </div>
                <div style={{ fontSize: 16, fontWeight: 800, color: user?.customerType ? "#2563eb" : "#94a3b8", marginTop: 2 }}>
                  {user?.customerType ? "Access Enabled" : "Not Enabled"}
                </div>
                {user?.customerType ? (
                  <Link to="/b2b" style={{ fontSize: 11, color: "#3b82f6", fontWeight: 700, marginTop: 2, display: "block" }}>
                    Go to B2B Catalog →
                  </Link>
                ) : (
                  <div style={{ fontSize: 11, color: "#94a3b8", fontWeight: 600, marginTop: 2 }}>
                    Contact admin to enable
                  </div>
                )}
              </div>
            </div>
          </div>

          <div style={{ textAlign: "center" }}>
            <button className="dash-logout" onClick={handleLogout}>
              <RiLogoutBoxLine /> Sign Out of Account
            </button>
          </div>
        </div>
      </main>

      <Footer />
    </>
  );
}

export default MyAccount;
